namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS education pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has contributed to open-source projects in computational geometry.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Operating Systems", Code = "CS 330", Description = "Covers process management, memory allocation, file systems, and concurrency. Includes hands-on kernel programming projects.", Credits = 4, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez worked at a major OS vendor for a decade before joining academia. She holds several patents in memory management.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Turing Jr.", InstructorBio = "Dr. Turing has taught calculus for over 20 years and authored a widely-used textbook on applied mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang's research focuses on numerical linear algebra and its applications in scientific computing.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Robert Feynman III", InstructorBio = "Dr. Feynman is known for his engaging lectures and has won multiple teaching awards for making physics accessible.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, Title = "Quantum Mechanics", Code = "PHYS 401", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, and spin.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Niels Bohr II", InstructorBio = "Dr. Bohr conducts research in quantum information theory and has published extensively in leading physics journals.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, Title = "English Composition", Code = "ENG 101", Description = "Develop clear, effective academic writing skills through essay assignments, peer review, and revision workshops.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. Emily Dickinson IV", InstructorBio = "Prof. Dickinson specializes in rhetoric and composition studies with a focus on digital literacy.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period to the present, examining themes of identity and democracy.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Mark Twain V", InstructorBio = "Dr. Twain is a leading scholar in 19th-century American literature with several critically acclaimed publications.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History to 1500", Code = "HIST 101", Description = "Survey of major civilizations, empires, and cultural exchanges from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Howard Carter II", InstructorBio = "Dr. Carter is an archaeologist-historian whose fieldwork in the Middle East informs his teaching of ancient civilizations.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 11, Title = "Machine Learning", Code = "CS 450", Description = "Foundations of machine learning: supervised and unsupervised learning, neural networks, and model evaluation techniques.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Andrew Ng Jr.", InstructorBio = "Dr. Ng has industry experience at leading AI companies and bridges the gap between theory and practical ML applications.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 12, Title = "Probability & Statistics", Code = "MATH 360", Description = "Probability theory, random variables, distributions, hypothesis testing, and confidence intervals.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Florence Nightingale II", InstructorBio = "Dr. Nightingale applies statistical methods to public health research and is passionate about data visualization.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In production, this would persist to a database.
        return request.CourseId > 0
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

