@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container py-4">
    <div class="text-center mb-5">
        <h1 class="display-4">University Course Catalog</h1>
        <p class="lead text-muted">Explore departments, discover courses, and enroll for the upcoming semester.</p>
    </div>

    <section class="mb-5">
        <h2 class="mb-3">Featured Courses</h2>
        <div class="row g-3">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-6 col-lg-4">
                    <div class="card h-100 border-primary">
                        <div class="card-body">
                            <span class="badge bg-primary mb-2">@course.Code</span>
                            <h5 class="card-title">@course.Title</h5>
                            <p class="card-text text-muted small">@course.DepartmentName &middot; @course.Credits credits</p>
                            <p class="card-text">@Truncate(course.Description, 100)</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mb-5">
        <h2 class="mb-3">Departments</h2>
        <div class="row g-3">
            @foreach (var dept in departments)
            {
                <div class="col-md-6 col-lg-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text text-muted">@dept.Description</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="text-center">
        <a href="/courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
        <a href="/enroll" class="btn btn-success btn-lg">Enroll Now</a>
    </section>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Courses - University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6 mb-2">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" @onkeyup="ApplyFilters" />
        </div>
        <div class="col-md-4 mb-2">
            <select class="form-select" @bind="selectedDepartmentId" @bind:after="ApplyFilters">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2 mb-2">
            <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
        </div>
    </div>

    @if (courses.Any())
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead class="table-light">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in courses)
                    {
                        <tr>
                            <td><strong>@course.Code</strong></td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td class="small">@course.Schedule</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @courses.Count course(s)</p>
    }
    else
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> courses = new();
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        selectedDepartmentId = DepartmentId ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        courses = CatalogService.GetCourses(searchTerm, selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        searchTerm = string.Empty;
        selectedDepartmentId = 0;
        ApplyFilters();
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Your enrollment request for <strong>@selectedCourseName</strong> has been submitted successfully.</p>
            <p>You will receive a confirmation at your university email within 2 business days.</p>
            <hr>
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
            <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another Request</button>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-lg-8">
                <EditForm Model="enrollmentRequest" OnValidSubmit="HandleSubmit" FormName="enrollment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="alert alert-danger" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <InputText id="studentName" class="form-control" @bind-Value="enrollmentRequest.StudentName" />
                        <ValidationMessage For="() => enrollmentRequest.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" @bind-Value="enrollmentRequest.StudentId" />
                        <div class="form-text">Enter your 6-10 character alphanumeric student ID (e.g., STU12345).</div>
                        <ValidationMessage For="() => enrollmentRequest.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseSelect" class="form-label">Course</label>
                        <InputSelect id="courseSelect" class="form-select" @bind-Value="enrollmentRequest.CourseId">
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.Code - @course.Title (@course.Credits cr)</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => enrollmentRequest.CourseId" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                    <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </EditForm>
            </div>

            <div class="col-lg-4">
                <div class="card bg-light">
                    <div class="card-body">
                        <h5 class="card-title">Need Help?</h5>
                        <p class="card-text small">
                            Contact the Registrar's Office at <strong>registrar&#64;university.edu</strong>
                            or visit Room 102 in the Administration Building.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest enrollmentRequest = new();
    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue)
        {
            enrollmentRequest.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(enrollmentRequest.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} - {course.Title}" : "Unknown Course";

        if (CatalogService.SubmitEnrollmentRequest(enrollmentRequest))
        {
            submitted = true;
        }
    }

    private void Reset()
    {
        enrollmentRequest = new EnrollmentRequest();
        submitted = false;
    }
}

